// Build lookup: ticker → existing row object
const psRows = $('Get Existing Price-Sales Data').all();
const psMap = {};
for (const row of psRows) {
  const t = row.json.ticker;
  if (t && t !== 'ticker') {
    psMap[t] = row.json;
  }
}

// Compute last Friday's date (workflow runs Sunday)
function getLastFriday() {
  const d = new Date();
  d.setUTCHours(0, 0, 0, 0);
  const dayOfWeek = d.getUTCDay();
  const daysBack = dayOfWeek === 0 ? 2 : (dayOfWeek + 2) % 7 || 7;
  d.setUTCDate(d.getUTCDate() - daysBack);
  return d.toISOString().split('T')[0];
}

function getBackfillFrom() {
  const d = new Date(Date.now() - 52 * 7 * 24 * 60 * 60 * 1000);
  return d.toISOString().split('T')[0];
}

function buildFmpTicker(ticker, exchange) {
  const usExchanges = ['NASDAQ', 'NYSE', 'OTC', 'AMEX'];
  if (usExchanges.includes(exchange)) return ticker;
  const suffixMap = {
    'NSE': `${ticker}.NS`, 'BSE': `${ticker}.BO`,
    'GETTEX': `${ticker}.F`, 'FWB': `${ticker}.F`,
    'DUS': `${ticker}.DU`, 'MIL': `${ticker}.MI`,
    'VIE': `${ticker}.VI`, 'BMV': `${ticker}.MX`,
    'DFM': `${ticker}.AE`, 'ASX': `${ticker}.AX`,
    'MYX': `${ticker}.KL`, 'EURONEXT': `${ticker}.PA`,
    'TRADEGATE': `${ticker}.TG`, 'NSENG': `${ticker}.LG`,
  };
  return suffixMap[exchange] || ticker;
}

const lastFriday = getLastFriday();
const backfillFrom = getBackfillFrom();
const tickers = $('Get Ticker List').all();
const results = [];

for (const item of tickers) {
  const { ticker, exchange } = item.json;
  if (!ticker) continue;

  const existing = psMap[ticker] || null;
  let mode;

  if (!existing) {
    mode = 'backfill';
  } else if (!existing.last_updated || existing.last_updated < lastFriday) {
    mode = 'update';
  } else {
    continue; // already current — skip
  }

  results.push({
    json: {
      ticker,
      exchange,
      fmp_ticker: buildFmpTicker(ticker, exchange),
      mode,
      last_friday: lastFriday,
      backfill_from: backfillFrom,
      existing: existing
    }
  });
}

return results;

// Access the income statement response and the prior context
const incomeData = $json;
const profileData = $('Fetch FMP Profile').item;
const classifyData = $('Build PS Map + Classify').item;

// Extract income statement array - could be in different places depending on response
let stmts = [];
if (Array.isArray(incomeData)) {
  stmts = incomeData;
} else if (incomeData && Array.isArray(incomeData.body)) {
  stmts = incomeData.body;
} else if (incomeData && incomeData.data && Array.isArray(incomeData.data)) {
  stmts = incomeData.data;
}

let revenue_ttm = null;
let revenue_error = null;

if (stmts.length === 0) {
  revenue_error = 'no_data';
} else {
  const quarters = stmts.slice(0, 4);
  revenue_ttm = quarters.reduce((sum, q) => sum + (parseFloat(q.revenue) || 0), 0);
  if (revenue_ttm === 0) {
    revenue_error = 'zero_revenue';
  }
}

// Extract profile data
let sharesOutstanding = null;
let profileArr = [];
if (Array.isArray(profileData.json)) {
  profileArr = profileData.json;
} else if (profileData.json && Array.isArray(profileData.json.body)) {
  profileArr = profileData.json.body;
} else if (profileData.json && Array.isArray(profileData.json.data)) {
  profileArr = profileData.json.data;
} else if (profileData.json && profileData.json.sharesOutstanding) {
  profileArr = [profileData.json];
}

if (profileArr.length > 0) {
  sharesOutstanding = profileArr[0].sharesOutstanding || null;
}

return {
  json: {
    ...classifyData.json,
    sharesOutstanding,
    revenue_ttm,
    revenue_error
  }
};

function getMedian(values) {
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2;
}

function isFriday(dateStr) {
  return new Date(dateStr + 'T12:00:00Z').getUTCDay() === 5;
}

const today = new Date().toISOString().split('T')[0];

const priceResponse = $json;
const revenueData = $('Compute Revenue TTM').item.json;

const ticker = revenueData.ticker;
const mode = revenueData.mode;
const last_friday = revenueData.last_friday;
const existing = revenueData.existing;
const shares = parseFloat(revenueData.sharesOutstanding);
const rev = parseFloat(revenueData.revenue_ttm);

// Validate inputs
if (!shares || !rev || shares <= 0 || rev <= 0) {
  return { json: { _skip: true, ticker, reason: `missing shares (${shares}) or revenue (${rev})` } };
}

// Get historical price data - handle different response shapes
let historical = [];
if (priceResponse && Array.isArray(priceResponse.historical)) {
  historical = priceResponse.historical;
} else if (priceResponse && priceResponse.body && Array.isArray(priceResponse.body.historical)) {
  historical = priceResponse.body.historical;
} else if (Array.isArray(priceResponse)) {
  historical = priceResponse;
}

if (historical.length === 0) {
  return { json: { _skip: true, ticker, reason: 'no historical price data' } };
}

let newHistory = [];

if (mode === 'backfill') {
  // Filter to Fridays, sort oldest first, take up to 52
  const fridays = historical
    .filter(d => isFriday(d.date))
    .sort((a, b) => a.date.localeCompare(b.date))
    .slice(-52);

  for (const day of fridays) {
    const price = parseFloat(day.close);
    if (!price || price <= 0) continue;
    const ps_val = parseFloat(((price * shares) / rev).toFixed(2));
    if (!isFinite(ps_val) || ps_val <= 0) continue;
    newHistory.push([day.date, ps_val]);
  }
} else {
  // Update: parse existing history, append new Friday entry
  let existing_history = [];
  try {
    existing_history = JSON.parse(existing.ps_history_json || '[]');
  } catch(e) { existing_history = []; }

  // Find the Friday entry from historical response
  const fridayEntry = historical.find(d => d.date === last_friday)
    || historical[0];

  if (!fridayEntry) {
    return { json: { _skip: true, ticker, reason: 'no Friday price found' } };
  }

  const price = parseFloat(fridayEntry.close);
  const ps_val = parseFloat(((price * shares) / rev).toFixed(2));
  if (!isFinite(ps_val) || ps_val <= 0) {
    return { json: { _skip: true, ticker, reason: 'invalid ps_val' } };
  }

  existing_history.push([last_friday, ps_val]);
  // Keep rolling 52-entry window
  if (existing_history.length > 52) {
    existing_history = existing_history.slice(existing_history.length - 52);
  }
  newHistory = existing_history;
}

if (newHistory.length === 0) {
  return { json: { _skip: true, ticker, reason: 'empty history after processing' } };
}

// Compute all stats from history
const values = newHistory.map(h => h[1]);
const ps_current = values[values.length - 1];
const ps_52w_high = parseFloat(Math.max(...values).toFixed(2));
const ps_52w_low = parseFloat(Math.min(...values).toFixed(2));
const ps_12m_median = parseFloat(getMedian(values).toFixed(2));

// ATH: sticky — never goes down
const prev_ath = mode === 'update'
  ? parseFloat(existing.ps_ath || 0)
  : 0;
const ps_ath = parseFloat(Math.max(prev_ath, ps_current, ps_52w_high).toFixed(2));
const pct_of_ath = parseFloat((ps_current / ps_ath).toFixed(2));

const first_recorded = mode === 'backfill'
  ? newHistory[0][0]
  : (existing.first_recorded || newHistory[0][0]);

return {
  json: {
    ticker,
    mode,
    ps_current,
    ps_ath,
    ps_52w_high,
    ps_52w_low,
    ps_12m_median,
    pct_of_ath,
    ps_history_json: JSON.stringify(newHistory),
    last_updated: last_friday,
    first_recorded,
    is_new_row: mode === 'backfill',
    _skip: false
  }
};

// Gather all processed items from Compute PS node
let allItems = [];
try {
  allItems = $('Compute PS + Build History').all();
} catch(e) {
  allItems = [];
}

const processed = allItems.filter(i => !i.json._skip);
const skipped = allItems.filter(i => i.json._skip);
const backfilled = processed.filter(i => i.json.mode === 'backfill').length;
const updated = processed.filter(i => i.json.mode === 'update').length;

return [{
  json: {
    run_date: new Date().toISOString().split('T')[0],
    backfilled,
    updated,
    skipped: skipped.length,
    total: backfilled + updated,
    run_at: new Date().toISOString()
  }
}];
